const respostaCompleta = $input.first().json.output || '';

// Separa pelos delimitadores ---
const blocos = respostaCompleta
  .split(/\n?---\n?/)
  .map(b => b.trim())
  .filter(b => b.length > 0);

// Retorna cada bloco como um item separado
return blocos.map(texto => ({ json: { texto } }));

